#!/usr/bin/env python3
"""Saturation Mask Decoder for Distributed Inference

Loads serialized saturation masks from model files for runtime application.

Supports both SafeTensors and GGUF formats, with automatic format detection.
Handles missing/corrupted metadata gracefully with fallback to all-active masks.

Module Functions:
  - load_saturation_masks(): Load masks from model file
  - load_cliff_scores(): Load per-layer cliff detection scores
  - parse_mask_metadata(): Extract masks from SafeTensors/GGUF

Usage:
  from saturation_mask_decoder import load_saturation_masks

  masks = load_saturation_masks("model.safetensors")
  if masks:
      for layer_id, mask in masks.items():
          if mask.is_frozen(neuron_idx):
              # Skip computation for this neuron
              pass

Integration Points:
  - aether: Apply masks in FFN inference loop
  - gnosis-uring: Register frozen neuron indices with scheduler
  - vLLM: Load masks at model initialization
  - llama.cpp: Inject masks into matmul kernels

Requirements:
  - torch >= 2.0 (for tensor I/O)
  - safetensors >= 0.4
  - numpy >= 2.0
"""

import argparse
import json
import logging
import pickle
import sys
from pathlib import Path
from typing import Any, Dict, List, Optional, Tuple

import numpy as np
import torch

logger = logging.getLogger(__name__)
logging.basicConfig(level=logging.INFO, format="%(asctime)s - %(levelname)s - %(message)s")


class LayerFrozenBitmask:
    """Runtime representation of frozen neurons in a layer."""

    def __init__(self, layer_id: int, num_neurons: int, frozen_indices: List[int]):
        self.layer_id = layer_id
        self.num_neurons = num_neurons
        self.frozen_indices = set(frozen_indices)

    def is_frozen(self, neuron_idx: int) -> bool:
        """Check if neuron is frozen."""
        return neuron_idx in self.frozen_indices

    def num_frozen(self) -> int:
        """Total number of frozen neurons."""
        return len(self.frozen_indices)

    def pct_frozen(self) -> float:
        """Percentage of frozen neurons."""
        return self.num_frozen() / self.num_neurons * 100.0 if self.num_neurons > 0 else 0.0

    def estimated_speedup(self) -> float:
        """Estimate speedup from freezing."""
        pct = self.pct_frozen() / 100.0
        return 1.0 + (pct * 0.1)

    def to_sparse_indices(self) -> np.ndarray:
        """Export frozen indices as numpy array for batched operations."""
        return np.array(sorted(self.frozen_indices), dtype=np.int32)

    def to_dense_mask(self) -> np.ndarray:
        """Export as dense boolean array (neuron_dim,)."""
        mask = np.zeros(self.num_neurons, dtype=np.bool_)
        for idx in self.frozen_indices:
            mask[idx] = True
        return mask

    @staticmethod
    def from_bytes(layer_id: int, num_neurons: int, data: bytes) -> "LayerFrozenBitmask":
        """Deserialize from bitpacked binary format."""
        frozen = []
        if data:
            for byte_idx, byte_val in enumerate(data):
                for bit_idx in range(8):
                    if byte_val & (1 << bit_idx):
                        idx = byte_idx * 8 + bit_idx
                        if idx < num_neurons:
                            frozen.append(idx)
        return LayerFrozenBitmask(layer_id, num_neurons, frozen)


def load_saturation_masks(
    model_path: str,
    fallback_to_empty: bool = True
) -> Optional[Dict[int, LayerFrozenBitmask]]:
    """
    Load saturation masks from model file (SafeTensors or GGUF).

    Args:
        model_path: Path to .safetensors or .gguf model file
        fallback_to_empty: If True, return empty dict on missing masks;
                          if False, return None

    Returns:
        Dict mapping layer_id -> LayerFrozenBitmask, or None if not found
    """
    model_path = Path(model_path)

    if not model_path.exists():
        logger.warning(f"Model file not found: {model_path}")
        return {} if fallback_to_empty else None

    try:
        if str(model_path).endswith(".safetensors"):
            return _load_safetensors_masks(str(model_path), fallback_to_empty)
        elif str(model_path).endswith(".gguf"):
            return _load_gguf_masks(str(model_path), fallback_to_empty)
        else:
            logger.warning(f"Unknown model format: {model_path}")
            return {} if fallback_to_empty else None
    except Exception as e:
        logger.error(f"Error loading masks: {e}")
        return {} if fallback_to_empty else None


def _load_safetensors_masks(
    model_path: str,
    fallback_to_empty: bool = True
) -> Optional[Dict[int, LayerFrozenBitmask]]:
    """Load masks from SafeTensors format."""
    from safetensors import safe_open

    try:
        with safe_open(model_path, framework="pt", device="cpu") as f:
            # Check if saturation masks exist
            if "__saturation_masks_blob__" not in f.keys():
                logger.debug("No saturation masks found in SafeTensors")
                return {} if fallback_to_empty else None

            # Load mask blob
            mask_blob = f.get_tensor("__saturation_masks_blob__").numpy().tobytes()

            # Deserialize
            masks = _deserialize_masks_blob(mask_blob)

            if masks:
                logger.info(f"Loaded {len(masks)} saturation masks from {model_path}")
            else:
                logger.warning("Mask blob found but empty after deserialization")

            return masks

    except Exception as e:
        logger.error(f"Error loading SafeTensors masks: {e}")
        return {} if fallback_to_empty else None


def _load_gguf_masks(
    gguf_path: str,
    fallback_to_empty: bool = True
) -> Optional[Dict[int, LayerFrozenBitmask]]:
    """Load masks from GGUF format."""
    try:
        from gguf import GGUFReader
    except ImportError:
        logger.error("gguf module not available. Install via: pip install gguf")
        return {} if fallback_to_empty else None

    try:
        reader = GGUFReader(gguf_path)

        # Check for saturation masks
        if "model.saturation_masks" not in reader.tensors:
            logger.debug("No saturation masks found in GGUF")
            return {} if fallback_to_empty else None

        # Load mask tensor and convert to bytes
        mask_tensor = reader.tensors["model.saturation_masks"]
        mask_blob = mask_tensor.astype(np.uint8).tobytes()

        # Deserialize
        masks = _deserialize_masks_blob(mask_blob)

        if masks:
            logger.info(f"Loaded {len(masks)} saturation masks from {gguf_path}")
        else:
            logger.warning("Mask tensor found but empty after deserialization")

        return masks

    except Exception as e:
        logger.error(f"Error loading GGUF masks: {e}")
        return {} if fallback_to_empty else None


def _deserialize_masks_blob(blob: bytes) -> Dict[int, LayerFrozenBitmask]:
    """Deserialize mask blob to dict of LayerFrozenBitmask objects."""
    if not blob:
        return {}

    try:
        offset = 0
        num_masks = int.from_bytes(blob[offset:offset+4], "little")
        offset += 4

        masks = {}
        for _ in range(num_masks):
            if offset + 12 > len(blob):
                logger.warning("Incomplete mask blob header")
                break

            layer_id = int.from_bytes(blob[offset:offset+4], "little")
            offset += 4
            num_neurons = int.from_bytes(blob[offset:offset+4], "little")
            offset += 4
            data_len = int.from_bytes(blob[offset:offset+4], "little")
            offset += 4

            if offset + data_len > len(blob):
                logger.warning(f"Incomplete mask data for layer {layer_id}")
                break

            mask_bytes = blob[offset:offset+data_len] if data_len > 0 else b""
            offset += data_len

            mask = LayerFrozenBitmask.from_bytes(layer_id, num_neurons, mask_bytes)
            masks[layer_id] = mask

        return masks

    except Exception as e:
        logger.error(f"Error deserializing mask blob: {e}")
        return {}


def load_cliff_scores(
    model_path: str,
    fallback_to_empty: bool = True
) -> Optional[Dict[int, float]]:
    """
    Load per-layer cliff detection scores from model metadata.

    Cliff scores indicate how sharply frozen neuron counts change over sequence.
    Used for detecting saturation patterns and potential layer skipping.

    Args:
        model_path: Path to model file
        fallback_to_empty: If True, return empty dict on missing data

    Returns:
        Dict mapping layer_id -> cliff_score (float), or None if not found
    """
    model_path = Path(model_path)

    if not model_path.exists():
        return {} if fallback_to_empty else None

    try:
        if str(model_path).endswith(".safetensors"):
            return _load_safetensors_cliff_scores(str(model_path), fallback_to_empty)
        elif str(model_path).endswith(".gguf"):
            return _load_gguf_cliff_scores(str(model_path), fallback_to_empty)
        elif str(model_path).endswith(".saturation.json"):
            return _load_json_cliff_scores(str(model_path), fallback_to_empty)
        else:
            # Try JSON sidecar
            json_path = str(model_path).replace(".safetensors", ".saturation.json")
            if Path(json_path).exists():
                return _load_json_cliff_scores(json_path, fallback_to_empty)
            return {} if fallback_to_empty else None

    except Exception as e:
        logger.error(f"Error loading cliff scores: {e}")
        return {} if fallback_to_empty else None


def _load_safetensors_cliff_scores(
    model_path: str,
    fallback_to_empty: bool = True
) -> Optional[Dict[int, float]]:
    """Load cliff scores from SafeTensors metadata JSON."""
    json_path = str(model_path).replace(".safetensors", ".saturation.json")
    if Path(json_path).exists():
        return _load_json_cliff_scores(json_path, fallback_to_empty)
    return {} if fallback_to_empty else None


def _load_gguf_cliff_scores(
    gguf_path: str,
    fallback_to_empty: bool = True
) -> Optional[Dict[int, float]]:
    """Load cliff scores from GGUF metadata."""
    try:
        from gguf import GGUFReader
    except ImportError:
        logger.error("gguf module not available")
        return {} if fallback_to_empty else None

    try:
        reader = GGUFReader(gguf_path)

        # Collect all cliff_score.{layer_id} keys
        cliff_scores = {}
        for key, value in reader.metadata.items():
            if key.startswith("model.cliff_score."):
                try:
                    layer_id = int(key.split(".")[-1])
                    cliff_scores[layer_id] = float(value)
                except (ValueError, IndexError):
                    continue

        return cliff_scores if cliff_scores else ({} if fallback_to_empty else None)

    except Exception as e:
        logger.error(f"Error loading GGUF cliff scores: {e}")
        return {} if fallback_to_empty else None


def _load_json_cliff_scores(
    json_path: str,
    fallback_to_empty: bool = True
) -> Optional[Dict[int, float]]:
    """Load cliff scores from JSON metadata file."""
    try:
        with open(json_path, "r") as f:
            data = json.load(f)

        cliff_scores = data.get("cliff_scores", {})

        # JSON keys are strings; convert to int
        cliff_scores = {int(k): v for k, v in cliff_scores.items()}

        return cliff_scores if cliff_scores else ({} if fallback_to_empty else None)

    except Exception as e:
        logger.error(f"Error loading JSON cliff scores: {e}")
        return {} if fallback_to_empty else None


def load_saturation_metadata(model_path: str) -> Optional[Dict[str, Any]]:
    """
    Load full saturation metadata (method, timestamp, creation info).

    Args:
        model_path: Path to model file or .saturation.json sidecar

    Returns:
        Dict with metadata, or None if not found
    """
    model_path = Path(model_path)

    if str(model_path).endswith(".saturation.json"):
        json_path = model_path
    else:
        json_path = Path(str(model_path).replace(".safetensors", ".saturation.json"))

    if not json_path.exists():
        logger.debug(f"No saturation metadata found at {json_path}")
        return None

    try:
        with open(json_path, "r") as f:
            return json.load(f)
    except Exception as e:
        logger.error(f"Error loading metadata: {e}")
        return None


def main():
    parser = argparse.ArgumentParser(description="Load and inspect saturation masks")
    parser.add_argument(
        "--model",
        type=str,
        required=True,
        help="Path to model file (.safetensors or .gguf)"
    )
    parser.add_argument(
        "--show-metadata",
        action="store_true",
        help="Show creation metadata"
    )
    parser.add_argument(
        "--show-cliff-scores",
        action="store_true",
        help="Show per-layer cliff scores"
    )
    parser.add_argument(
        "--layer-summary",
        action="store_true",
        help="Show summary for each layer"
    )
    parser.add_argument(
        "--export-pickle",
        type=str,
        default=None,
        help="Export masks as pickle file"
    )
    parser.add_argument(
        "--export-json",
        type=str,
        default=None,
        help="Export masks as JSON"
    )

    args = parser.parse_args()

    # Load masks
    masks = load_saturation_masks(args.model)

    if not masks:
        logger.info("No saturation masks found in model")
        return

    print("\n" + "="*70)
    print(f"SATURATION MASKS: {args.model}")
    print("="*70)
    print(f"Total layers with masks: {len(masks)}\n")

    # Show metadata
    if args.show_metadata:
        metadata = load_saturation_metadata(args.model)
        if metadata:
            print("METADATA:")
            print(json.dumps(metadata, indent=2))
            print()

    # Show cliff scores
    if args.show_cliff_scores:
        cliff_scores = load_cliff_scores(args.model)
        if cliff_scores:
            print("CLIFF SCORES (saturation detection confidence):")
            for layer_id in sorted(cliff_scores.keys()):
                print(f"  Layer {layer_id:3d}: {cliff_scores[layer_id]:.3f}")
            print()

    # Layer summary
    if args.layer_summary:
        print("PER-LAYER SUMMARY:")
        print(f"{'Layer':<8} {'Frozen':<10} {'Pct':<8} {'Speedup':<10}")
        print("-" * 40)
        for layer_id in sorted(masks.keys()):
            mask = masks[layer_id]
            print(
                f"{layer_id:<8} {mask.num_frozen():<10} "
                f"{mask.pct_frozen():<8.1f} {mask.estimated_speedup():<10.2f}x"
            )
        print()

    # Summary stats
    total_frozen = sum(m.num_frozen() for m in masks.values())
    total_neurons = sum(m.num_neurons for m in masks.values())
    avg_speedup = np.mean([m.estimated_speedup() for m in masks.values()])

    print("SUMMARY:")
    print(f"  Total neurons: {total_neurons:,}")
    print(f"  Total frozen: {total_frozen:,} ({total_frozen/total_neurons*100:.1f}%)")
    print(f"  Average speedup estimate: {avg_speedup:.2f}x")
    print("="*70 + "\n")

    # Exports
    if args.export_pickle:
        logger.info(f"Exporting to pickle: {args.export_pickle}")
        pickle.dump(masks, open(args.export_pickle, "wb"))

    if args.export_json:
        logger.info(f"Exporting to JSON: {args.export_json}")
        export_data = {
            "num_layers": len(masks),
            "layers": {
                str(layer_id): {
                    "num_frozen": mask.num_frozen(),
                    "num_neurons": mask.num_neurons,
                    "pct_frozen": mask.pct_frozen(),
                    "estimated_speedup": mask.estimated_speedup(),
                    "frozen_indices": sorted(mask.frozen_indices)[:100],  # First 100 for readability
                }
                for layer_id, mask in masks.items()
            }
        }
        with open(args.export_json, "w") as f:
            json.dump(export_data, f, indent=2)


if __name__ == "__main__":
    main()
